// Generate personalized email content
const lead = $input.first().json;
const firstName = lead.fields['First Name'] || 'there';
const serviceNeeded = lead.fields['Service Needed'] || 'HVAC system';
const lossReason = (lead.fields['Loss Reason'] || '').toLowerCase();
const companyName = $env.COMPANY_NAME || 'our team';
const companyPhone = $env.COMPANY_PHONE || '';
const discountAmount = $env.REACTIVATION_DISCOUNT || '50';

// Determine value proposition based on loss reason
let valueProp = '';
let ctaText = '';

if (lossReason.includes('price') || lossReason.includes('expensive')) {
  valueProp = `We're currently offering <strong>$${discountAmount} off any diagnostic visit</strong> for returning customers.`;
  ctaText = 'claim your discount';
} else if (lossReason.includes('timing') || lossReason.includes('busy')) {
  valueProp = `We have same-day and next-day appointments available, and our technicians work around your schedule.`;
  ctaText = 'find a time that works';
} else {
  valueProp = `We're offering <strong>$${discountAmount} off any diagnostic visit</strong> this month, plus priority scheduling for returning customers.`;
  ctaText = 'schedule your appointment';
}

const emailHtml = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">
  <p style="font-size: 16px; color: #333;">Hi ${firstName},</p>

  <p style="font-size: 16px; color: #333; line-height: 1.6;">
    I wanted to follow up on my text from yesterday. I know life gets busy, so I wanted to make it easy for you.
  </p>

  <p style="font-size: 16px; color: #333; line-height: 1.6;">
    ${valueProp} Our technicians arrive in fully-stocked trucks, so most issues get diagnosed <strong>AND</strong> fixed in the same visit.
  </p>

  <p style="font-size: 16px; color: #333; line-height: 1.6;">
    If your ${serviceNeeded} is still giving you trouble, just reply to this email or call us at <a href="tel:${companyPhone}" style="color: #0066cc;">${companyPhone}</a>.
  </p>

  <p style="font-size: 16px; color: #333; line-height: 1.6;">
    No pressure either way - just wanted to make sure you knew we're here if you need us.
  </p>

  <p style="font-size: 16px; color: #333; margin-top: 30px;">
    Best,<br>
    <strong>The ${companyName} Team</strong>
  </p>

  <hr style="border: none; border-top: 1px solid #eee; margin: 30px 0;">

  <p style="font-size: 12px; color: #888;">
    You're receiving this because you previously inquired about our services. 
    <a href="#" style="color: #888;">Unsubscribe</a>
  </p>
</div>
`;

const subject = `Quick question about your ${serviceNeeded} needs`;

return {
  json: {
    lead: lead,
    email: {
      to: lead.fields['Email'],
      subject: subject,
      htmlContent: emailHtml,
      ctaText: ctaText
    }
  }
};
